    49→  align-items: center;
    50→  justify-content: space-between;
    51→  padding: 16px 20px 12px;
    52→  background: linear-gradient(180deg, var(--bg) 0%, transparent 100%);
    53→  position: relative;
    54→  z-index: 10;
    55→  flex-shrink: 0;
