    57→
    58→.header-title {
    59→  display: flex;
    60→  align-items: center;
    61→  gap: 10px;
    62→}
    63→
    64→.logo-dot {
    65→  width: 10px;
    66→  height: 10px;
    67→  background: var(--accent);
    68→  border-radius: 50%;
    69→  box-shadow: 0 0 8px var(--accent-glow);
    70→  animation: pulse-dot 3s ease-in-out infinite;
