   657→  to   { box-shadow: 0 4px 32px rgba(83, 52, 131, 0.25), 0 0 0 3px rgba(83, 52, 131, 0.35); }
   658→}
   659→
   660→/* Wake word button active state */
   661→.icon-btn.wake-active {
   662→  color: var(--accent);
   663→  background: rgba(233, 69, 96, 0.12);
   664→  border-color: rgba(233, 69, 96, 0.3);
   665→  animation: wake-btn-pulse 2.5s ease-in-out infinite;
