   670→  50%       { box-shadow: 0 0 0 4px rgba(233, 69, 96, 0.15); }
   671→}
   672→
   673→/* ===== Brainstorm dual-transcript ===== */
   674→.transcript-section-label {
   675→  display: block;
   676→  font-size: 0.72rem;
   677→  font-weight: 700;
   678→  letter-spacing: 0.08em;
   679→  text-transform: uppercase;
   680→  color: rgba(163, 121, 221, 0.85);
   681→  margin-bottom: 6px;
   682→}
   683→
   684→.transcript-section-label--raw {
   685→  color: var(--text-muted);
   686→}
   687→
   688→.transcript-raw-wrap {
