   700→
   701→/* Live transcript: auto-scroll container in brainstorm mode */
   702→.live-transcript.brainstorm-mode {
   703→  max-height: 130px;
   704→  overflow-y: auto;
   705→  scroll-behavior: smooth;
   706→}
   707→
   708→/* ===== Utilities ===== */
   709→@keyframes fade-in {
   710→  from { opacity: 0; }
   711→  to   { opacity: 1; }
   712→}
